1	import { Schema } from "effect";
2	import { TrimmedNonEmptyString } from "./baseSchemas";
3	
4	export const DEFAULT_TERMINAL_ID = "default";
5	
6	const TrimmedNonEmptyStringSchema = TrimmedNonEmptyString;
7	const TerminalColsSchema = Schema.Int.check(Schema.isGreaterThanOrEqualTo(20)).check(
8	  Schema.isLessThanOrEqualTo(400),
9	);
10	const TerminalRowsSchema = Schema.Int.check(Schema.isGreaterThanOrEqualTo(5)).check(
11	  Schema.isLessThanOrEqualTo(200),
12	);
13	const TerminalIdSchema = TrimmedNonEmptyStringSchema.check(Schema.isMaxLength(128));
14	const TerminalEnvKeySchema = Schema.String.check(
15	  Schema.isPattern(/^[A-Za-z_][A-Za-z0-9_]*$/),
16	).check(Schema.isMaxLength(128));
17	const TerminalEnvValueSchema = Schema.String.check(Schema.isMaxLength(8_192));
18	const TerminalEnvSchema = Schema.Record(TerminalEnvKeySchema, TerminalEnvValueSchema).check(
19	  Schema.isMaxProperties(128),
20	);
21	
22	const TerminalIdWithDefaultSchema = TerminalIdSchema.pipe(
23	  Schema.withDecodingDefault(() => DEFAULT_TERMINAL_ID),
24	);
25	
26	export const TerminalThreadInput = Schema.Struct({
27	  threadId: TrimmedNonEmptyStringSchema,
28	});
29	export type TerminalThreadInput = Schema.Codec.Encoded<typeof TerminalThreadInput>;
30	
31	const TerminalSessionInput = Schema.Struct({
32	  ...TerminalThreadInput.fields,
33	  terminalId: TerminalIdWithDefaultSchema,
34	});
35	export type TerminalSessionInput = Schema.Codec.Encoded<typeof TerminalSessionInput>;
36	
37	export const TerminalOpenInput = Schema.Struct({
38	  ...TerminalSessionInput.fields,
39	  cwd: TrimmedNonEmptyStringSchema,
40	  cols: Schema.optional(TerminalColsSchema),
41	  rows: Schema.optional(TerminalRowsSchema),
42	  env: Schema.optional(TerminalEnvSchema),
43	});
44	export type TerminalOpenInput = Schema.Codec.Encoded<typeof TerminalOpenInput>;
45	
46	export const TerminalWriteInput = Schema.Struct({
47	  ...TerminalSessionInput.fields,
48	  data: Schema.String.check(Schema.isNonEmpty()).check(Schema.isMaxLength(65_536)),
49	});
50	export type TerminalWriteInput = Schema.Codec.Encoded<typeof TerminalWriteInput>;
51	
52	export const TerminalResizeInput = Schema.Struct({
53	  ...TerminalSessionInput.fields,
54	  cols: TerminalColsSchema,
55	  rows: TerminalRowsSchema,
56	});
57	export type TerminalResizeInput = Schema.Codec.Encoded<typeof TerminalResizeInput>;
58	
59	export const TerminalClearInput = TerminalSessionInput;
60	export type TerminalClearInput = Schema.Codec.Encoded<typeof TerminalClearInput>;
61	
62	export const TerminalRestartInput = Schema.Struct({
63	  ...TerminalThreadInput.fields,
64	  cwd: TrimmedNonEmptyStringSchema,
65	  cols: TerminalColsSchema,
66	  rows: TerminalRowsSchema,
67	  env: Schema.optional(TerminalEnvSchema),
68	});
69	
70	export const TerminalCloseInput = Schema.Struct({
71	  ...TerminalThreadInput.fields,
72	  terminalId: Schema.optional(TerminalIdSchema),
73	  deleteHistory: Schema.optional(Schema.Boolean),
74	});
75	export type TerminalCloseInput = Schema.Codec.Encoded<typeof TerminalCloseInput>;
76	
77	export const TerminalSessionStatus = Schema.Literals(["starting", "running", "exited", "error"]);
78	export type TerminalSessionStatus = typeof TerminalSessionStatus.Type;
79	
80	export const TerminalSessionSnapshot = Schema.Struct({
81	  threadId: Schema.String.check(Schema.isNonEmpty()),
82	  terminalId: Schema.String.check(Schema.isNonEmpty()),
83	  cwd: Schema.String.check(Schema.isNonEmpty()),
84	  status: TerminalSessionStatus,
85	  pid: Schema.NullOr(Schema.Int.check(Schema.isGreaterThan(0))),
86	  history: Schema.String,
87	  exitCode: Schema.NullOr(Schema.Int),
88	  exitSignal: Schema.NullOr(Schema.Int),
89	  updatedAt: Schema.String,
90	});
91	export type TerminalSessionSnapshot = typeof TerminalSessionSnapshot.Type;
92	
93	const TerminalEventBaseSchema = Schema.Struct({
94	  threadId: Schema.String.check(Schema.isNonEmpty()),
95	  terminalId: Schema.String.check(Schema.isNonEmpty()),
96	  createdAt: Schema.String,
97	});
98	
99	const TerminalStartedEvent = Schema.Struct({
100	  ...TerminalEventBaseSchema.fields,
101	  type: Schema.Literal("started"),
102	  snapshot: TerminalSessionSnapshot,
103	});
104	
105	const TerminalOutputEvent = Schema.Struct({
106	  ...TerminalEventBaseSchema.fields,
107	  type: Schema.Literal("output"),
108	  data: Schema.String,
109	});
110	
111	const TerminalExitedEvent = Schema.Struct({
112	  ...TerminalEventBaseSchema.fields,
113	  type: Schema.Literal("exited"),
114	  exitCode: Schema.NullOr(Schema.Int),
115	  exitSignal: Schema.NullOr(Schema.Int),
116	});
117	
118	const TerminalErrorEvent = Schema.Struct({
119	  ...TerminalEventBaseSchema.fields,
120	  type: Schema.Literal("error"),
121	  message: Schema.String.check(Schema.isNonEmpty()),
122	});
123	
124	const TerminalClearedEvent = Schema.Struct({
125	  ...TerminalEventBaseSchema.fields,
126	  type: Schema.Literal("cleared"),
127	});
128	
129	const TerminalRestartedEvent = Schema.Struct({
130	  ...TerminalEventBaseSchema.fields,
131	  type: Schema.Literal("restarted"),
132	  snapshot: TerminalSessionSnapshot,
133	});
134	
135	const TerminalActivityEvent = Schema.Struct({
136	  ...TerminalEventBaseSchema.fields,
137	  type: Schema.Literal("activity"),
138	  hasRunningSubprocess: Schema.Boolean,
139	});
140	
141	export const TerminalEvent = Schema.Union([
142	  TerminalStartedEvent,
143	  TerminalOutputEvent,
144	  TerminalExitedEvent,
145	  TerminalErrorEvent,
146	  TerminalClearedEvent,
147	  TerminalRestartedEvent,
148	  TerminalActivityEvent,
149	]);
150	export type TerminalEvent = typeof TerminalEvent.Type;
