1	import { Schema } from "effect";
2	import { NonNegativeInt, PositiveInt, TrimmedNonEmptyString } from "./baseSchemas";
3	
4	const TrimmedNonEmptyStringSchema = TrimmedNonEmptyString;
5	
6	// Domain Types
7	
8	export const GitStackedAction = Schema.Literals(["commit", "commit_push", "commit_push_pr"]);
9	export type GitStackedAction = typeof GitStackedAction.Type;
10	const GitCommitStepStatus = Schema.Literals(["created", "skipped_no_changes"]);
11	const GitPushStepStatus = Schema.Literals([
12	  "pushed",
13	  "skipped_not_requested",
14	  "skipped_up_to_date",
15	]);
16	const GitBranchStepStatus = Schema.Literals(["created", "skipped_not_requested"]);
17	const GitPrStepStatus = Schema.Literals([
18	  "created",
19	  "opened_existing",
20	  "skipped_not_requested",
21	]);
22	const GitStatusPrState = Schema.Literals(["open", "closed", "merged"]);
23	
24	export const GitBranch = Schema.Struct({
25	  name: TrimmedNonEmptyStringSchema,
26	  isRemote: Schema.optional(Schema.Boolean),
27	  remoteName: Schema.optional(TrimmedNonEmptyStringSchema),
28	  current: Schema.Boolean,
29	  isDefault: Schema.Boolean,
30	  worktreePath: TrimmedNonEmptyStringSchema.pipe(Schema.NullOr),
31	});
32	export type GitBranch = typeof GitBranch.Type;
33	
34	const GitWorktree = Schema.Struct({
35	  path: TrimmedNonEmptyStringSchema,
36	  branch: TrimmedNonEmptyStringSchema,
37	});
38	
39	// RPC Inputs
40	
41	export const GitStatusInput = Schema.Struct({
42	  cwd: TrimmedNonEmptyStringSchema,
43	});
44	export type GitStatusInput = typeof GitStatusInput.Type;
45	
46	export const GitPullInput = Schema.Struct({
47	  cwd: TrimmedNonEmptyStringSchema,
48	});
49	export type GitPullInput = typeof GitPullInput.Type;
50	
51	export const GitRunStackedActionInput = Schema.Struct({
52	  cwd: TrimmedNonEmptyStringSchema,
53	  action: GitStackedAction,
54	  commitMessage: Schema.optional(TrimmedNonEmptyStringSchema.check(Schema.isMaxLength(10_000))),
55	  featureBranch: Schema.optional(Schema.Boolean),
56	});
57	export type GitRunStackedActionInput = typeof GitRunStackedActionInput.Type;
58	
59	export const GitListBranchesInput = Schema.Struct({
60	  cwd: TrimmedNonEmptyStringSchema,
61	});
62	export type GitListBranchesInput = typeof GitListBranchesInput.Type;
63	
64	export const GitCreateWorktreeInput = Schema.Struct({
65	  cwd: TrimmedNonEmptyStringSchema,
66	  branch: TrimmedNonEmptyStringSchema,
67	  newBranch: TrimmedNonEmptyStringSchema,
68	  path: Schema.NullOr(TrimmedNonEmptyStringSchema),
69	});
70	export type GitCreateWorktreeInput = typeof GitCreateWorktreeInput.Type;
71	
72	export const GitRemoveWorktreeInput = Schema.Struct({
73	  cwd: TrimmedNonEmptyStringSchema,
74	  path: TrimmedNonEmptyStringSchema,
75	  force: Schema.optional(Schema.Boolean),
76	});
77	export type GitRemoveWorktreeInput = typeof GitRemoveWorktreeInput.Type;
78	
79	export const GitCreateBranchInput = Schema.Struct({
80	  cwd: TrimmedNonEmptyStringSchema,
81	  branch: TrimmedNonEmptyStringSchema,
82	});
83	export type GitCreateBranchInput = typeof GitCreateBranchInput.Type;
84	
85	export const GitCheckoutInput = Schema.Struct({
86	  cwd: TrimmedNonEmptyStringSchema,
87	  branch: TrimmedNonEmptyStringSchema,
88	});
89	export type GitCheckoutInput = typeof GitCheckoutInput.Type;
90	
91	export const GitInitInput = Schema.Struct({
92	  cwd: TrimmedNonEmptyStringSchema,
93	});
94	export type GitInitInput = typeof GitInitInput.Type;
95	
96	// RPC Results
97	
98	const GitStatusPr = Schema.Struct({
99	  number: PositiveInt,
100	  title: TrimmedNonEmptyStringSchema,
101	  url: Schema.String,
102	  baseBranch: TrimmedNonEmptyStringSchema,
103	  headBranch: TrimmedNonEmptyStringSchema,
104	  state: GitStatusPrState,
105	});
106	
107	export const GitStatusResult = Schema.Struct({
108	  branch: TrimmedNonEmptyStringSchema.pipe(Schema.NullOr),
109	  hasWorkingTreeChanges: Schema.Boolean,
110	  workingTree: Schema.Struct({
111	    files: Schema.Array(
112	      Schema.Struct({
113	        path: TrimmedNonEmptyStringSchema,
114	        insertions: NonNegativeInt,
115	        deletions: NonNegativeInt,
116	      }),
117	    ),
118	    insertions: NonNegativeInt,
119	    deletions: NonNegativeInt,
120	  }),
121	  hasUpstream: Schema.Boolean,
122	  aheadCount: NonNegativeInt,
123	  behindCount: NonNegativeInt,
124	  pr: Schema.NullOr(GitStatusPr),
125	});
126	export type GitStatusResult = typeof GitStatusResult.Type;
