---

### 6. CSS Integration Strategy

#### 6a. New CSS custom properties in `apps/web/src/index.css`

Add the new scoped variables to both the `:root` block and the `@variant dark` block so that they have sensible fallback values even before JavaScript runs. These defaults match the `t3-light` and `t3-dark` palettes respectively.

Inside the existing `:root { ... }` block, append:

```css
/* Scoped theme surfaces */
--sidebar-background: #f9fafb;
--sidebar-foreground: var(--foreground);
--sidebar-border: var(--border);
--sidebar-accent: rgba(0, 0, 0, 0.06);
--sidebar-accent-foreground: #111827;
--editor-background: var(--background);
--editor-foreground: var(--foreground);
--editor-line-highlight: rgba(0, 0, 0, 0.03);
--terminal-background: #1e1e1e;
--terminal-foreground: #d4d4d4;
--terminal-cursor: #d4d4d4;
--statusbar-background: #f3f4f6;
--statusbar-foreground: #374151;
--statusbar-border: var(--border);
```

Inside the existing `@variant dark { ... }` block, append the dark counterparts:

```css
--sidebar-background: #09090b;
--sidebar-foreground: var(--foreground);
--sidebar-border: var(--border);
--sidebar-accent: rgba(255, 255, 255, 0.06);
--sidebar-accent-foreground: #f9fafb;
--editor-background: var(--background);
--editor-foreground: var(--foreground);
--editor-line-highlight: rgba(255, 255, 255, 0.03);
--terminal-background: #09090b;
--terminal-foreground: #d4d4d4;
--terminal-cursor: #d4d4d4;
--statusbar-background: #09090b;
--statusbar-foreground: #d1d5db;
--statusbar-border: var(--border);
```

Add corresponding Tailwind v4 `@theme inline` entries so these are usable as utility classes:

```css
--color-sidebar-background: var(--sidebar-background);
--color-sidebar-foreground: var(--sidebar-foreground);
--color-sidebar-border: var(--sidebar-border);
--color-sidebar-accent: var(--sidebar-accent);
--color-sidebar-accent-foreground: var(--sidebar-accent-foreground);
--color-editor-background: var(--editor-background);
--color-editor-foreground: var(--editor-foreground);
--color-editor-line-highlight: var(--editor-line-highlight);
--color-terminal-background: var(--terminal-background);
--color-terminal-foreground: var(--terminal-foreground);
--color-terminal-cursor: var(--terminal-cursor);
--color-statusbar-background: var(--statusbar-background);
--color-statusbar-foreground: var(--statusbar-foreground);
--color-statusbar-border: var(--statusbar-border);
```

This also resolves the existing `bg-sidebar`, `text-sidebar-foreground` references in `sidebar.tsx` which currently have no explicit variable backing -- they will now properly resolve via `--color-sidebar-*` variables. The existing shadcn sidebar component uses `bg-sidebar` and `text-sidebar-foreground`, and in Tailwind v4 these resolve to `--color-sidebar` and `--color-sidebar-foreground`. We should define `--color-sidebar: var(--sidebar-background)` (note: shadcn convention uses `bg-sidebar` to mean the sidebar background) and `--color-sidebar-ring: var(--ring)` in the `@theme inline` block.

#### 6b. How CSS custom properties are applied at runtime

When a theme is selected, the hook iterates over all keys in the theme's `colors` object and calls `document.documentElement.style.setProperty("--" + key, value)` for each one. This overrides the CSS-level defaults from `:root` / `@variant dark`.

When the user switches themes, the previous overrides are cleared first by calling `document.documentElement.style.removeProperty("--" + key)` for every key in `ThemeColors`, then the new values are applied. This ensures we don't leave stale overrides from a previous theme.

The `.dark` class is toggled based on `ThemeDefinition.mode`: if `mode === "dark"`, add `.dark`; if `mode === "light"`, remove `.dark`. This preserves all existing `dark:` Tailwind utility behavior.

---

### 7. Refactored `useTheme` Hook

The refactored `apps/web/src/hooks/useTheme.ts` changes are:

**New localStorage key**: `t3code:theme-preference` (stores a `ThemePreference` value: `"system"`, `"t3-light"`, `"t3-dark"`, or `"t3-midnight"`)

**Migration logic**: On first load, check for the old key `t3code:theme`. If found:
- `"light"` -> migrate to `"t3-light"`
- `"dark"` -> migrate to `"t3-dark"`
- `"system"` -> migrate to `"system"`
- Write to the new key, delete the old key.

**Snapshot structure changes**:

```typescript
type ThemeSnapshot = {
  preference: ThemePreference;   // "system" | "t3-light" | "t3-dark" | "t3-midnight"
  systemDark: boolean;
};
```

**Core resolution logic**:

```typescript
function resolveThemeId(preference: ThemePreference, systemDark: boolean): ThemeId {
  if (preference === "system") {
    return systemDark ? "t3-dark" : "t3-light";
  }
  return preference; // Already a ThemeId
}
```

**CSS application function** (replaces the existing `applyTheme`):

```typescript
function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  const definition = getThemeDefinition(themeId);

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class based on theme mode
  document.documentElement.classList.toggle("dark", definition.mode === "dark");

  // Set color-scheme
  document.documentElement.style.setProperty("color-scheme", definition.mode);

  // Clear all previous theme overrides, then apply new ones
  for (const key of THEME_COLOR_KEYS) {
    document.documentElement.style.removeProperty(`--${key}`);
  }
  for (const [key, value] of Object.entries(definition.colors)) {
    document.documentElement.style.setProperty(`--${key}`, value);
  }

  // Set data attribute for potential CSS selectors
  document.documentElement.dataset.theme = themeId;

  if (suppressTransitions) {
    void document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}
```

**Hook return type** (backward compatible):

```typescript
export function useTheme() {
  // ...
  return {
    theme: snapshot.preference,          // ThemePreference
    themeId,                             // ThemeId (resolved)
    resolvedTheme,                       // "light" | "dark" (backward compat)
    setTheme,                            // (next: ThemePreference) => void
  } as const;
}
```

The critical backward compatibility point: `resolvedTheme` remains `"light" | "dark"`, derived from `getThemeMode(themeId)`. Every existing consumer (`DiffWorkerPoolProvider`, `ChatMarkdown`, `DiffPanel`, `ChatView`) only reads `resolvedTheme` to pick between light/dark diff themes, so they continue working without any changes.

**Module-level initialization** (prevents flash, identical to current approach):

```typescript
// Run immediately on module load
const initialPreference = getStoredPreference(); // reads new key, with migration
const initialSystemDark = getSystemDark();
const initialThemeId = resolveThemeId(initialPreference, initialSystemDark);
applyTheme(initialThemeId);
```

---

### 8. Settings Page Changes

In `apps/web/src/routes/_chat.settings.tsx`:

- Remove the `THEME_OPTIONS` constant (lines 25-41)
- Remove the inline Appearance section JSX (lines 202-243)
- Import and render `<ThemeSelector />` in its place
- The `ThemeSelector` receives no props; it calls `useTheme()` internally

---

### 9. ThemeSelector Component Design

`apps/web/src/components/ThemeSelector.tsx`:

```
+------------------------------------------------------+
| Appearance                                           |
| Choose your preferred color theme.                   |
|                                                      |
|  [ System ]  (toggle, when active shows which        |
|               theme it resolves to)                   |
|                                                      |
|  +-------------+ +-------------+ +----------------+  |
|  | T3 Light    | | T3 Dark     | | Midnight       |  |
|  |             | |             | |                |  |
|  | [swatch]    | | [swatch]    | | [swatch]       |  |
|  | ........... | | ........... | | ...............|  |
|  | bg  fg  acc | | bg  fg  acc | | bg   fg   acc  |  |
|  +-------------+ +-------------+ +----------------+  |
|                                                      |
|  Active: T3 Dark                                     |
+------------------------------------------------------+
```

Each theme card shows:
- Theme name
- A mini swatch strip with 4-5 color circles: background, foreground, primary, accent, sidebar-background
- A selected/active indicator (border highlight + badge, matching the current pattern on the settings page)
- Click to select

There is also a "System" toggle at the top. When "System" is selected, the card corresponding to the resolved theme gets a subtle "Auto" badge.

The component structure:

```typescript
function ThemeSelector() {
  const { theme, themeId, setTheme } = useTheme();
  const isSystem = theme === "system";

  return (
    <section className="rounded-2xl border border-border bg-card p-5">
      <div className="mb-4">
        <h2 className="text-sm font-medium text-foreground">Appearance</h2>
        <p className="mt-1 text-xs text-muted-foreground">
          Choose your preferred color theme.
        </p>
      </div>

      {/* System toggle */}
      <div className="mb-4 flex items-center justify-between rounded-lg border border-border bg-background px-3 py-2">
        <div>
          <p className="text-sm font-medium text-foreground">Match system</p>
          <p className="text-xs text-muted-foreground">
            Automatically switch between light and dark.
          </p>
        </div>
        <Switch
          checked={isSystem}
          onCheckedChange={(checked) => {
            setTheme(checked ? "system" : themeId);
          }}
        />
      </div>

      {/* Theme cards grid */}
      <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
        {THEME_IDS.map((id) => {
          const def = getThemeDefinition(id);
          const isActive = isSystem ? themeId === id : theme === id;
          return (
            <ThemeCard
              key={id}
              definition={def}
              isActive={isActive}
              isAutoSelected={isSystem && themeId === id}
              onSelect={() => setTheme(isSystem ? "system" : id)}
              disabled={isSystem}
            />
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme: <span className="font-medium text-foreground">
          {getThemeDefinition(themeId).name}
        </span>
        {isSystem ? " (system)" : ""}
      </p>
    </section>
  );
}
```

`ThemeCard` is a local sub-component that renders the swatch strip:

```typescript
function ThemeCard({ definition, isActive, isAutoSelected, onSelect, disabled }) {
  const { colors } = definition;
  const swatchColors = [
    colors.background,
    colors.foreground,
    colors.primary,
    colors["sidebar-background"],
    colors["terminal-background"],
  ];

  return (
    <button
      type="button"
      role="radio"
      aria-checked={isActive}
      disabled={disabled && !isActive}
      className={cn(
        "flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors",
        isActive
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
        disabled && !isActive && "opacity-50 cursor-default"
      )}
      onClick={onSelect}
    >
      <span className="text-xs font-medium">{definition.name}</span>
      <div className="flex gap-1.5">
        {swatchColors.map((color, i) => (
          <span
            key={i}
            className="size-4 rounded-full border border-border/50"
            style={{ backgroundColor: color }}
          />
        ))}
      </div>
      {isActive && (
        <span className="rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          {isAutoSelected ? "Auto" : "Selected"}
        </span>
      )}
    </button>
  );
}
```

