import { useCallback, useEffect, useSyncExternalStore } from "react";
import type { ThemeId, ThemeMode, ThemePreference } from "@t3tools/contracts";
import {
  getThemeDefinition,
  getThemeMode,
  THEME_COLOR_KEYS,
} from "@t3tools/shared/theme";

// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

const STORAGE_KEY = "t3code:theme-preference";
const OLD_STORAGE_KEY = "t3code:theme";
const MEDIA_QUERY = "(prefers-color-scheme: dark)";

const VALID_PREFERENCES = new Set<string>(["system", "t3-light", "t3-dark", "t3-midnight"]);

// ---------------------------------------------------------------------------
// Internal state
// ---------------------------------------------------------------------------

type ThemeSnapshot = {
  preference: ThemePreference;
  systemDark: boolean;
};

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeSnapshot | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function getSystemDark(): boolean {
  return window.matchMedia(MEDIA_QUERY).matches;
}

/** Migrate the old "t3code:theme" key to the new "t3code:theme-preference" key. */
function migrateOldKey(): void {
  const old = localStorage.getItem(OLD_STORAGE_KEY);
  if (old === null) return;

  const map: Record<string, ThemePreference> = {
    system: "system",
    light: "t3-light",
    dark: "t3-dark",
  };
  const migrated: ThemePreference = map[old] ?? "system";
  localStorage.setItem(STORAGE_KEY, migrated);
  localStorage.removeItem(OLD_STORAGE_KEY);
}

function getStored(): ThemePreference {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (raw && VALID_PREFERENCES.has(raw)) return raw as ThemePreference;
  return "system";
}

function resolveThemeId(preference: ThemePreference, systemDark: boolean): ThemeId {
  if (preference === "system") {
    return systemDark ? "t3-dark" : "t3-light";
  }
  return preference;
}

// ---------------------------------------------------------------------------
// CSS application
// ---------------------------------------------------------------------------

function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  const definition = getThemeDefinition(themeId);

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Toggle .dark class for Tailwind dark: utilities
  document.documentElement.classList.toggle("dark", definition.mode === "dark");

  // Set color-scheme for native browser styling
  document.documentElement.style.setProperty("color-scheme", definition.mode);

  // Clear previous theme overrides, then apply new ones
  for (const key of THEME_COLOR_KEYS) {
    document.documentElement.style.removeProperty(`--${key}`);
  }
  for (const key of THEME_COLOR_KEYS) {
    const value = definition.colors[key];
    document.documentElement.style.setProperty(`--${key}`, value);
  }

  // Data attribute for optional CSS selectors
  document.documentElement.dataset.theme = themeId;

  if (suppressTransitions) {
    // Force a reflow so the no-transitions class takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// ---------------------------------------------------------------------------
// Module-level init (prevents flash of wrong theme)
// ---------------------------------------------------------------------------

migrateOldKey();
const initialPreference = getStored();
const initialThemeId = resolveThemeId(initialPreference, getSystemDark());
applyTheme(initialThemeId);

// ---------------------------------------------------------------------------
// External store for useSyncExternalStore
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeSnapshot {
  const preference = getStored();
  const systemDark = preference === "system" ? getSystemDark() : false;

  if (
    lastSnapshot &&
    lastSnapshot.preference === preference &&
    lastSnapshot.systemDark === systemDark
  ) {
    return lastSnapshot;
  }

  lastSnapshot = { preference, systemDark };
  return lastSnapshot;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for system preference changes
  const mq = window.matchMedia(MEDIA_QUERY);
  const handleChange = () => {
    const pref = getStored();
    if (pref === "system") {
      applyTheme(resolveThemeId("system", getSystemDark()), true);
    }
    emitChange();
  };
  mq.addEventListener("change", handleChange);

  // Listen for storage changes from other tabs
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      const pref = getStored();
      applyTheme(resolveThemeId(pref, getSystemDark()), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    mq.removeEventListener("change", handleChange);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const snapshot = useSyncExternalStore(subscribe, getSnapshot);
  const preference = snapshot.preference;
  const themeId: ThemeId = resolveThemeId(preference, snapshot.systemDark);
  const resolvedTheme: ThemeMode = getThemeMode(themeId);

  const setTheme = useCallback((next: ThemePreference) => {
    localStorage.setItem(STORAGE_KEY, next);
    const nextId = resolveThemeId(next, getSystemDark());
    applyTheme(nextId, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return {
    /** The raw user preference ("system" | "t3-light" | "t3-dark" | "t3-midnight"). */
    theme: preference,
    /** The resolved ThemeId after system preference resolution. */
    themeId,
    /** "light" | "dark" — backward compatible for diff theme resolution etc. */
    resolvedTheme,
    /** Update the theme preference. */
    setTheme,
  } as const;
}

