import type { ThemeId } from "@t3tools/contracts";
import {
  getThemeDefinition,
  THEME_IDS,
  type ThemeDefinition,
} from "@t3tools/shared/theme";

import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";
import { Switch } from "./ui/switch";

// ---------------------------------------------------------------------------
// Swatch preview — shows 5 representative colors from a theme palette
// ---------------------------------------------------------------------------

const SWATCH_KEYS = [
  "background",
  "foreground",
  "primary",
  "sidebar-background",
  "terminal-background",
] as const;

function ThemeCard({
  definition,
  isActive,
  isAutoSelected,
  onSelect,
  disabled,
}: {
  definition: ThemeDefinition;
  isActive: boolean;
  isAutoSelected: boolean;
  onSelect: () => void;
  disabled: boolean;
}) {
  return (
    <button
      type="button"
      role="radio"
      aria-checked={isActive}
      aria-label={definition.name}
      disabled={disabled && !isActive}
      className={cn(
        "flex flex-col gap-2.5 rounded-xl border p-3 text-left transition-colors",
        isActive
          ? "border-primary/60 bg-primary/8"
          : "border-border bg-background hover:bg-accent",
        disabled && !isActive && "cursor-default opacity-50",
      )}
      onClick={onSelect}
    >
      <span className="text-xs font-medium text-foreground">{definition.name}</span>

      {/* Color swatches */}
      <div className="flex gap-1.5">
        {SWATCH_KEYS.map((key) => (
          <span
            key={key}
            className="size-4 rounded-full border border-border/50"
            style={{ backgroundColor: definition.colors[key] }}
          />
        ))}
      </div>

      {isActive && (
        <span className="self-start rounded bg-primary/14 px-1.5 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
          {isAutoSelected ? "Auto" : "Selected"}
        </span>
      )}
    </button>
  );
}

// ---------------------------------------------------------------------------
// ThemeSelector — drop-in replacement for the Appearance section in settings
// ---------------------------------------------------------------------------

export function ThemeSelector() {
  const { theme, themeId, setTheme } = useTheme();
  const isSystem = theme === "system";

  return (
    <section className="rounded-2xl border border-border bg-card p-5">
      <div className="mb-4">
        <h2 className="text-sm font-medium text-foreground">Appearance</h2>
        <p className="mt-1 text-xs text-muted-foreground">
          Choose your preferred color theme.
        </p>
      </div>

      {/* System toggle */}
      <div className="mb-4 flex items-center justify-between rounded-lg border border-border bg-background px-3 py-2">
        <div>
          <p className="text-sm font-medium text-foreground">Match system</p>
          <p className="text-xs text-muted-foreground">
            Automatically switch between light and dark.
          </p>
        </div>
        <Switch
          checked={isSystem}
          onCheckedChange={(checked: boolean) => {
            setTheme(checked ? "system" : themeId);
          }}
          aria-label="Match system theme"
        />
      </div>

      {/* Theme cards */}
      <div
        className="grid grid-cols-3 gap-3"
        role="radiogroup"
        aria-label="Color theme"
      >
        {THEME_IDS.map((id: ThemeId) => {
          const def = getThemeDefinition(id);
          const isActive = isSystem ? themeId === id : theme === id;
          return (
            <ThemeCard
              key={id}
              definition={def}
              isActive={isActive}
              isAutoSelected={isSystem && themeId === id}
              onSelect={() => setTheme(id)}
              disabled={isSystem}
            />
          );
        })}
      </div>

      <p className="mt-4 text-xs text-muted-foreground">
        Active theme:{" "}
        <span className="font-medium text-foreground">
          {getThemeDefinition(themeId).name}
        </span>
        {isSystem ? " (system)" : ""}
      </p>
    </section>
  );
}

